    auth_root=require_within(root,root/"authorizations"/job["authorizationId"],"authorization");authorization=_json(auth_root/"authorization.json");auth_commit=_json(auth_root/"commit.json");reservation=_json(root/"authorization-state"/job["authorizationId"]/"reservation.json")
    if auth_commit.get("authorizationSha256")!=sha256_file(auth_root/"authorization.json") or authorization.get("decisionCommitSha256")!=job["decisionCommitSha256"] or reservation.get("jobId")!=job["jobId"] or reservation.get("runId")!=job["runId"]:raise ValueError("The one-run authorization is invalid.")
