    uncertainty={"schemaVersion":"1.0","runId":job["runId"],"jobId":job["jobId"],"datasetId":job["datasetId"],"deploymentId":job["deploymentId"],"decisionId":job["decisionId"],"assessmentId":job["assessmentId"],"selectedModelId":job["selectedModelId"],"selectedModelParameterSha256":job["selectedModelParameterSha256"],"uncertaintyStatus":"pending_selected_model_calibration","lowerRaw":None,"upperRaw":None,"lowerReported":None,"upperReported":None,"nominalCoverage":None,"historicalCoverage":None,"calibrationMethod":None,"residualCount":None,"isPredictionInterval":False,"calibratedOnSyntheticData":False,"rmseFallbackAllowed":False,"bundledP13RangeReused":False,"syntheticRangeReused":False,"limitations":["Selected-model calibration has not been governed or executed.","Assessment residuals are retained as evidence but no interval is inferred from them."],"generatedAt":generated};_write(artifacts/"forecast_uncertainty.json",uncertainty)
    cases=pd.read_csv(canonical_case);history=[{"period":_period(int(r.epi_year),int(r.epi_week)),"cases":int(r.cases)} for r in cases.tail(52).itertuples()];_write(artifacts/"chart_data.json",{"schemaVersion":"1.0","runId":job["runId"],"history":history,"forecast":{"period":target_period,"cases":reported},"empiricalRange":None})
